+    #[test]
+    fn csv_nrows_limits_rows() {
+        let input = "x\n1\n2\n3\n4\n5\n";
+        let opts = CsvReadOptions {
+            nrows: Some(3),
+            ..Default::default()
+        };
+        let frame = read_csv_with_options(input, &opts).expect("parse");
+        assert_eq!(frame.index().len(), 3);
